export const getGetLikeStatusUrl = (params: GetLikeStatusParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/likes/status?${stringifiedParams}`
    : `/api/likes/status`;
};

export const getLikeStatus = async (
  params: GetLikeStatusParams,
  options?: RequestInit,
): Promise<LikeResult> => {
  return customFetch<LikeResult>(getGetLikeStatusUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetLikeStatusQueryKey = (params?: GetLikeStatusParams) => {
  return [`/api/likes/status`, ...(params ? [params] : [])] as const;
};

export const getGetLikeStatusQueryOptions = <
  TData = Awaited<ReturnType<typeof getLikeStatus>>,
  TError = ErrorType<unknown>,
>(
  params: GetLikeStatusParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getLikeStatus>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetLikeStatusQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getLikeStatus>>> = ({
    signal,
  }) => getLikeStatus(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getLikeStatus>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetLikeStatusQueryResult = NonNullable<
  Awaited<ReturnType<typeof getLikeStatus>>
>;
export type GetLikeStatusQueryError = ErrorType<unknown>;

export function useGetLikeStatus<
  TData = Awaited<ReturnType<typeof getLikeStatus>>,
  TError = ErrorType<unknown>,
>(
  params: GetLikeStatusParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getLikeStatus>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetLikeStatusQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

